#!/bin/bash
set -e
echo "=== CMDB Enterprise Setup ==="
mkdir -p server public

echo "[1/7] docker-compose.yml"  ; echo ""       | base64 -d > docker-compose.yml

echo "[2/7] Dockerfile"
cat > Dockerfile << 'EOF'
FROM node:20-alpine
WORKDIR /app
COPY server/package*.json ./
RUN npm install --omit=dev
COPY server/server.js ./
COPY public/ ./public/
VOLUME ["/data"]
ENV DATA_DIR=/data
ENV PORT=3000
EXPOSE 3000
HEALTHCHECK --interval=30s --timeout=5s --start-period=10s \
  CMD wget -qO- http://localhost:3000/api/auth/me || exit 1
CMD ["node", "server.js"]
EOF

echo "[3/7] server/package.json"  ; echo ""   | base64 -d > server/package.json
echo "[4/7] server/server.js"     ; echo ""  | base64 -d > server/server.js
echo "[5/7] public/cmdb.html"     ; echo ""        | base64 -d > public/cmdb.html
echo "[6/7] public/cmdbAPI.js"    ; echo ""      | base64 -d > public/cmdbAPI.js
echo "[7/7] public/cmdb-agent.ps1"; echo ""   | base64 -d > public/cmdb-agent.ps1

echo ""
echo "=== Criando pasta de livros ==="
sudo mkdir -p /opt/livros
sudo chown $(whoami):$(whoami) /opt/livros

echo ""
echo "=== Criando configuração do Kavita (BaseUrl=/biblioteca/) ==="
sudo mkdir -p /opt/kavita-settings
sudo tee /opt/kavita-settings/appsettings.json > /dev/null << 'JSONEOF'
{
  "Logging": {
    "LogLevel": {
      "Default": "Information",
      "Microsoft": "Warning",
      "Microsoft.Hosting.Lifetime": "Information"
    }
  },
  "AllowedHosts": "*",
  "Kavita": {
    "BaseUrl": "/biblioteca/",
    "Port": 5000
  }
}
JSONEOF
sudo chmod 644 /opt/kavita-settings/appsettings.json
echo "appsettings.json criado em /opt/kavita-settings/"

echo ""
echo "=== Parando containers antigos ==="
docker compose down --remove-orphans

echo ""
echo "=== Subindo containers ==="
docker compose up -d --build

echo ""
echo "=== Aguardando Kavita ficar healthy ==="
for i in $(seq 1 12); do
  STATUS=$(docker inspect --format='{{.State.Health.Status}}' kavita 2>/dev/null || echo "unknown")
  echo "  [$i/12] kavita: $STATUS"
  if [ "$STATUS" = "healthy" ]; then break; fi
  sleep 5
done

echo ""
docker compose ps

echo ""
IP=$(hostname -I | awk '{print $1}')
echo "=== Pronto! ==="
echo "CMDB:       http://${IP}:3000"
echo "Biblioteca: aba Biblioteca no CMDB"
